local CS = CS
local typeofBtObjectView = typeof(CardEHT.BtObjectView)
local LBubbleStick = LxRequire("LApp.gameplay.Common.LBubbleStick")
--------------------------------------------------------------------------------
---@class LFightBaseObj
local LFightBaseObj = LxClass("LFightBaseObj", nil)

function LFightBaseObj:LFightBaseObj()

    self._side = 0 -- 0 左边 1 右边

    self._btObjectView = nil --c#控件
    ---@type LDisplaySpine
    self._displayObj = nil
    self._rootTrans = nil

    self._seqCom = SequenceCom:New()
end

function LFightBaseObj:Create(data)
    self._data = data
    self._battleUnit = data.battleUnit
    self._objType = data.objType
    self._rootTrans = data.rootTrans
    self._side = data.side
    self._layerName = data.layerName

    self:SetDirectionBySide(self._side)
    --self._pos = data.pos
    self._localPosition = data.pos or Vector3.New(-100,0,0)

    self._randZ = math.random(100, 999) * 0.0000001
    self._aniShowEffectRef  = gModelHero:GetShowEffectById(data.heroEffId)

    self._rootTrans = data.parentTran
    self._spineName = self._aniShowEffectRef.prefabName
    self._scale = data.scale or 1

    self:InitActor()
    self:InitDisplay()
end

function LFightBaseObj:OnLoaded()
    self:SetPosition(self._localPosition)
    self:SetDirection(self._direction)
    self:InitBtObjectView()
    self:PlayIdleAni()
    self._displayObj:SetScale(self._scale)
    --出生动画时候才显示

    self._displayObj:SetRenderLayer(self._layerName)
    self._isReady = true

    local completeFunc = self._data.onComplete
    if completeFunc then
        completeFunc()
    end
end

function LFightBaseObj:SetPara(data)
    self._side = data.side
    self:SetDirectionBySide(self._side)
    self._localPosition = data.pos
    self:SetPosition(self._localPosition)
    self:SetDirection(self._direction)
end

function LFightBaseObj:SetDirectionBySide(side)
    self._direction = LFightConst.DIRECTION_LEFT
    if side == LFightConst.ACTON_TEAM_A then
        self._direction = LFightConst.DIRECTION_RIGHT
    end
end

function LFightBaseObj:IsObjReady()
    return self._isReady
end

function LFightBaseObj:InitBtObjectView()
    local dpTrans = self._displayObj:GetSpineTrans()
    local dpGo = dpTrans.gameObject

    local comp = dpGo:GetComponent(typeofBtObjectView)
    if(not comp) then
        comp = dpGo:AddComponent(typeofBtObjectView)
    end
    comp:SetRandZ(self._randZ)
    self._btObjectView = comp
end

function LFightBaseObj:SetDirection(dir)
    self._direction = dir
    self._displayObj:SetFlipX(dir ~= LFightConst.DIRECTION_RIGHT)
end

function LFightBaseObj:ToOppositeDirection()
    local dire = LFightConst.DIRECTION_RIGHT
    if dire == self._direction then
        dire = LFightConst.DIRECTION_LEFT
    end
    self:SetDirection(dire)
end



function LFightBaseObj:InitActor()
    self._aniActor = LFightAniActor:New(self._battleUnit,self)
    self._moveActor = LFightMoveActor:New(self._battleUnit,self)
end

function LFightBaseObj:InitDisplay()
    if not self._spineName then
        return
    end

    local dp = LDisplaySpine:New()
    self._displayObj = dp
    dp:CreateSpine(self._rootTrans, self._spineName)
    dp:SetScale(self._scale)
    dp:SetLoadedFunction(function()
        self:OnLoaded()
    end)
    dp:SetAnimationCompleteFunc(function(...)
        self:OnAnimationComplete(...)
    end)

    dp:StartLoad()
end

function LFightBaseObj:SetPosition(pos)
    --printInfoN("LFightBaseObj:SetPosition(pos)")
    pos.z = pos.y * 0.01 + self._randZ
    self._localPosition = pos
    if not self._displayObj:IsDpValid() then
        return
    end
    self._moveActor:StopMove()
    self._displayObj:GetDisplayTrans().localPosition = self._localPosition
end

function LFightBaseObj:GetPosition()
    if not self._displayObj:IsDpValid() then
        return self._localPosition
    end
    return self._displayObj:GetDisplayTrans().localPosition
end

function LFightBaseObj:GetGridPos()
    return self:GetPosition()
end

function LFightBaseObj:GetSide()
    return self._side
end

function LFightBaseObj:OnAnimationComplete(animateName)
    if animateName == LSpineAniConst.hit1 then
        self:PlayIdleAni()
    end
end

function LFightBaseObj:StartMove(pos,time,ignoreY)
    --printInfoN("LFightBaseObj:StartMove(pos,time,ignoreY)")
    self:ChangeDirToPos(pos)
    if ignoreY then
        local curPos = self:GetPosition()
        local startPos = Vector3.New(curPos.x,pos.y,curPos.z)
        self:SetPosition(startPos)
    end

    self._moveActor:MoveTo(pos,time)
end

function LFightBaseObj:GetTargetPos()
    if not self._moveActor then return end
    return self._moveActor:GetTargetPos()
end


function LFightBaseObj:PlayAni(animationName,bLoop,time,mixTime)
    self._aniActor:PlayAni(animationName,bLoop,time,mixTime)
end

function LFightBaseObj:SetRenderOrder(order)
    if self._displayObj then
        self._displayObj:SetRenderOrder(order)
    end
end

function LFightBaseObj:StartJumpTo(atkPos, topPos, moveTime,num)
    self._moveActor:JumpTo(atkPos, topPos, moveTime, num)
end

function LFightBaseObj:OnRun(time)
    self._moveActor:OnRun(time)
    self._aniActor:OnRun(time)
    if self._bubbleStick then self._bubbleStick:OnRun(time) end
    return true
end

function LFightBaseObj:ChangeDirToPos(tarPos)
    local dir = self._direction
    local pos = self:GetPosition()
    if pos.x < tarPos.x then
        dir = LFightConst.DIRECTION_RIGHT
    elseif pos.x > tarPos.x then
        dir = LFightConst.DIRECTION_LEFT
    end
    if dir ~= self._direction then
        self:SetDirection(dir)
    end
end

function LFightBaseObj:GetObjectType()
    return self._objType
end

function LFightBaseObj:GetDpObject()
    return self._displayObj
end

function LFightBaseObj:CreateBubbleStick(prefabName,offset)
    if not self._displayObj:IsDpValid() then return end

    local bubbleStick = self._bubbleStick
    if not bubbleStick then
        bubbleStick = LBubbleStick:New()
    end

    local dpTarns = self._displayObj:GetDisplayTrans()
    local topNodePos = self:GetTopNodePos()
    local nowPos = dpTarns.position
    bubbleStick:CreateBubble(prefabName)
    local pos = topNodePos - nowPos + offset
    bubbleStick:SetHeroTrans(dpTarns,pos)
    self._bubbleStick = bubbleStick
end

function LFightBaseObj:GetTopNodePos()
    if not self._displayObj then
        return Vector3.zero
    end

    if not self._displayObj:IsDpValid() then return  Vector3.zero end
    local topNode = self._topNodeTrans
    if not topNode then
        local dpTrans = self._displayObj:GetDisplayTrans()
        topNode = CS.FindTrans(dpTrans,"TopNode")
        self._topNodeTrans = topNode
    end
    return topNode.position
end

function LFightBaseObj:ShowBubbleStick(str,time,startTime,prefabName,offset)
    local bubbleStick = self._bubbleStick
    self:CreateBubbleStick(prefabName,offset)
    bubbleStick = self._bubbleStick
    if not bubbleStick then return end
    bubbleStick:SetContent(str,time,startTime)
    bubbleStick:SetVisible(true)
end

function LFightBaseObj:GetBtObjectView()
    return self._btObjectView
end

function LFightBaseObj:GetDirection()
    return self._direction
end

function LFightBaseObj:PlayIdleAni()
    self:PlayAni(LSpineAniConst.idle,true)
end

function LFightBaseObj:ToUpperLayer()
    if not self._displayObj then
        self._isUpperLayer = true
        return
    end
    local layer = "ObjectUp"
    self._displayObj:SetRenderLayer(layer)
end

function LFightBaseObj:ToLowerLayer()
    if not self._displayObj then
        self._isUpperLayer = false
        return
    end
    local layer = "Object"
    self._displayObj:SetRenderLayer(layer)
end

function LFightBaseObj:StartFade(time)
    if not self._displayObj then
        return
    end

    local tweenSeq = self._seqCom:CreateSeq("alphaSeq")
    local alphaFunc = function(value)
        self._displayObj:SetAlpha(value)
    end
    local alphaTween = YXTween.TweenFloat(1,0,time,alphaFunc):SetEase(DG.Tweening.Ease.InSine)
    tweenSeq:Append(alphaTween)
    tweenSeq:PlayForward()
end

function LFightBaseObj:ResetAlpha()
    if not self._displayObj then
        return
    end
    self._displayObj:SetAlpha(1)
    self._seqCom:DeleteSeq("alphaSeq")
end

function LFightBaseObj:PlayAni_Actor(ani,loop,mixTime)
    local disObj = self:GetDpObject()
    disObj:SetAnimationTimeScale(1)
    disObj:PlayAnimation(0,ani,loop,false,mixTime)
end

function LFightBaseObj:SetAniTimeScale_Actor(timeScale)
    local disObj = self:GetDpObject()
    disObj:SetAnimationTimeScale(timeScale)
end

function LFightBaseObj:GetDisplayObj()
    return self._displayObj
end

function LFightBaseObj:Destroy()

    if self._displayObj then
        self._displayObj:Destroy()
        self._displayObj = nil
    end

    if self._bubbleStick then
        self._bubbleStick:DestroyBubble()
        self._bubbleStick = nil
    end

    if self._seqCom then
        self._seqCom:Destroy()
        self._seqCom= nil
    end

    table.removeall(self)
end



return LFightBaseObj
